import React, { useState, useRef, useEffect, useCallback } from 'react';
import PageContent from './PageContent';
import CoverPage from './CoverPage';

function BackCover() {
  return (
    <div className="back-cover" style={{ gridColumn: 'span 2' }}>
      <style>{`
        .back-cover {
          background:linear-gradient(135deg,#12100e 0%,#1a1510 100%);
          display:flex; align-items:center; justify-content:center;
        }
        .bc-inner { text-align:center; padding:30px; }
        .bc-star { font-size:28px; color:rgba(240,192,64,.25); margin-bottom:18px; }
        .bc-text {
          font-family:'IM Fell English',serif; font-style:italic;
          font-size:clamp(9px,1.3vw,13px); color:rgba(240,220,160,.4);
          line-height:1.75; max-width:180px; margin:0 auto 18px;
        }
        .bc-rule { width:36px; height:1px; margin:0 auto 14px; background:linear-gradient(90deg,transparent,rgba(240,192,64,.25),transparent); }
        .bc-name {
          font-family:'Cinzel',serif; font-size:clamp(7px,.95vw,9.5px);
          letter-spacing:.4em; color:rgba(240,192,64,.2);
        }
      `}</style>
      <div className="bc-inner">
        <div className="bc-star">✦</div>
        <p className="bc-text">A journey through the cosmos — from the first photon to the last question we dare to ask.</p>
        <div className="bc-rule" />
        <p className="bc-name">THE END</p>
      </div>
    </div>
  );
}

export default function Book({ book }) {
  const pages = book.pages.map((p, i) => ({ ...p, pageNum: i + 1 }));
  const totalSpreads = Math.ceil(pages.length / 2) + 1; // 0=cover, ..., last=back
  const [spread, setSpread] = useState(0);
  const [flipping, setFlipping] = useState(false);
  const [flipDir, setFlipDir] = useState(null);
  const [particles, setParticles] = useState([]);
  const timerRef = useRef(null);

  const isCover = spread === 0;
  const isLast = spread === totalSpreads - 1;

  // which pages are visible
  const leftPage  = spread > 0 ? pages[(spread - 1) * 2]     ?? null : null;
  const rightPage = spread > 0 && !isLast ? pages[(spread - 1) * 2 + 1] ?? null : null;

  const spawnParticles = () => {
    const pts = Array.from({ length: 14 }, (_, i) => ({
      id: Date.now() + i,
      x: 42 + Math.random() * 16, y: 20 + Math.random() * 60,
      vx: (Math.random() - .5) * 70, vy: -25 - Math.random() * 45,
    }));
    setParticles(pts);
    setTimeout(() => setParticles([]), 950);
  };

  const flip = useCallback((dir) => {
    if (flipping) return;
    if (dir === 'forward' && isLast) return;
    if (dir === 'backward' && isCover) return;
    setFlipping(true);
    setFlipDir(dir);
    spawnParticles();
    timerRef.current = setTimeout(() => {
      setSpread(s => s + (dir === 'forward' ? 1 : -1));
      setFlipping(false);
      setFlipDir(null);
    }, 680);
  }, [flipping, isLast, isCover]);

  useEffect(() => {
    const handler = (e) => {
      if (e.key === 'ArrowRight' || e.key === 'ArrowDown') flip('forward');
      if (e.key === 'ArrowLeft'  || e.key === 'ArrowUp')   flip('backward');
    };
    window.addEventListener('keydown', handler);
    return () => { window.removeEventListener('keydown', handler); clearTimeout(timerRef.current); };
  }, [flip]);

  const progress = (spread / (totalSpreads - 1)) * 100;
  const spreadLabel = isCover ? 'Cover' : isLast ? 'End'
    : `${(spread-1)*2+1}–${Math.min((spread-1)*2+2, pages.length)} / ${pages.length}`;

  return (
    <div className="book-wrap">
      <style>{`
        @keyframes flipFwd { 0%{transform:rotateY(0)} 100%{transform:rotateY(-180deg)} }
        @keyframes flipBwd { 0%{transform:rotateY(0)} 100%{transform:rotateY(180deg)} }
        @keyframes ptFly { 0%{opacity:1;transform:translate(0,0) scale(1)} 100%{opacity:0;transform:translate(var(--vx),var(--vy)) scale(.2)} }

        .book-wrap { display:flex; flex-direction:column; align-items:center; gap:24px; position:relative; z-index:10; width:100%; }

        .book-stage {
          perspective:2200px;
          width:min(860px,95vw);
          position:relative;
        }
        .book-shadow {
          position:absolute; bottom:-28px; left:10%; right:10%; height:36px;
          background:radial-gradient(ellipse,rgba(0,0,0,.6) 0%,transparent 70%);
          filter:blur(10px);
        }
        .book {
          width:100%; aspect-ratio:2/1.35;
          position:relative; transform-style:preserve-3d;
          filter:drop-shadow(0 30px 60px rgba(0,0,0,.8));
        }

        .spread {
          position:absolute; inset:0;
          display:grid; grid-template-columns:1fr 1fr;
          border-radius:3px; overflow:hidden;
        }

        .book-spine {
          position:absolute; top:0; bottom:0; left:50%; transform:translateX(-50%);
          width:9px; z-index:20;
          background:linear-gradient(180deg,#2a1f0a,#4a3520 50%,#2a1f0a);
          box-shadow:-2px 0 10px rgba(0,0,0,.45),2px 0 10px rgba(0,0,0,.45);
        }

        /* flip overlay */
        .flip-overlay {
          position:absolute; inset:0;
          display:grid; grid-template-columns:1fr 1fr;
          pointer-events:none; z-index:30; overflow:hidden;
        }
        .flip-half { position:relative; overflow:hidden; }
        .flip-half.animating {
          transform-style:preserve-3d;
          backface-visibility:hidden;
        }
        .flip-half.fwd { transform-origin:left center; animation:flipFwd .68s cubic-bezier(.4,0,.2,1) forwards; }
        .flip-half.bwd { transform-origin:right center; animation:flipBwd .68s cubic-bezier(.4,0,.2,1) forwards; }
        .flip-face, .flip-back {
          position:absolute; inset:0;
          backface-visibility:hidden;
        }
        .flip-back { transform:rotateY(180deg); background:var(--parchment); }

        /* particles */
        .ptl-layer { position:absolute; inset:0; pointer-events:none; z-index:50; overflow:hidden; }
        .ptl {
          position:absolute; width:4px; height:4px; border-radius:50%;
          background:radial-gradient(circle,#f0c040,rgba(255,255,255,.5));
          animation:ptFly .95s ease-out forwards;
        }

        /* click zones */
        .cz {
          position:absolute; top:0; bottom:0; width:20%; z-index:25;
          cursor:pointer; opacity:0; transition:opacity .2s;
          display:flex; align-items:center;
        }
        .cz:hover { opacity:1; }
        .cz-l { left:0; background:linear-gradient(90deg,rgba(240,192,64,.04),transparent); justify-content:flex-start; padding-left:14px; }
        .cz-r { right:0; background:linear-gradient(270deg,rgba(240,192,64,.04),transparent); justify-content:flex-end; padding-right:14px; }
        .cz-icon { font-size:20px; color:rgba(240,192,64,.45); }

        /* controls */
        .controls { display:flex; align-items:center; gap:20px; }
        .nav-btn {
          width:50px; height:50px; border-radius:50%;
          background:rgba(240,192,64,.07); border:1px solid rgba(240,192,64,.22);
          color:rgba(240,192,64,.7); font-size:18px;
          display:flex; align-items:center; justify-content:center;
          transition:all .22s;
        }
        .nav-btn:hover:not(:disabled) {
          background:rgba(240,192,64,.16); border-color:rgba(240,192,64,.5);
          color:#f0c040; transform:scale(1.1);
          box-shadow:0 0 18px rgba(240,192,64,.2);
        }
        .nav-btn:disabled { opacity:.18; cursor:not-allowed; }

        .progress-track { flex:1; max-width:180px; height:2px; background:rgba(255,255,255,.08); border-radius:2px; overflow:hidden; }
        .progress-fill { height:100%; background:linear-gradient(90deg,rgba(240,192,64,.35),rgba(240,192,64,.8)); transition:width .7s cubic-bezier(.4,0,.2,1); border-radius:2px; }

        .spread-label { font-family:'Cinzel',serif; font-size:9.5px; letter-spacing:.2em; color:rgba(240,192,64,.3); min-width:80px; text-align:center; }
        .key-hint { font-size:9.5px; letter-spacing:.2em; color:rgba(255,255,255,.12); text-transform:uppercase; }
      `}</style>

      <div className="book-stage">
        <div className="book-shadow" />
        <div className="book">
          {/* current spread */}
          <div className="spread">
            {isCover ? <CoverPage book={book} /> :
             isLast  ? (
               <>
                 {leftPage  ? <PageContent page={leftPage}  side="left"  /> : <div style={{background:'var(--parchment)'}}/>}
                 <BackCover />
               </>
             ) : (
               <>
                 {leftPage  ? <PageContent page={leftPage}  side="left"  /> : <div style={{background:'var(--parchment)'}}/>}
                 {rightPage ? <PageContent page={rightPage} side="right" /> : <div style={{background:'var(--parchment)'}}/>}
               </>
             )}
          </div>

          {/* spine */}
          <div className="book-spine" />

          {/* flip overlay */}
          {flipping && (
            <div className="flip-overlay">
              {flipDir === 'forward' ? (
                <>
                  <div className="flip-half" style={{background:'var(--parchment)'}} />
                  <div className="flip-half animating fwd">
                    <div className="flip-face">
                      {rightPage ? <PageContent page={rightPage} side="right" /> : <div style={{background:'var(--parchment)',height:'100%'}}/>}
                    </div>
                    <div className="flip-back" />
                  </div>
                </>
              ) : (
                <>
                  <div className="flip-half animating bwd">
                    <div className="flip-face">
                      {leftPage ? <PageContent page={leftPage} side="left" /> : <div style={{background:'var(--parchment)',height:'100%'}}/>}
                    </div>
                    <div className="flip-back" />
                  </div>
                  <div className="flip-half" style={{background:'var(--parchment)'}} />
                </>
              )}
            </div>
          )}

          {/* particles */}
          <div className="ptl-layer">
            {particles.map(p => (
              <div key={p.id} className="ptl" style={{
                left:`${p.x}%`, top:`${p.y}%`,
                '--vx':`${p.vx}px`, '--vy':`${p.vy}px`,
              }} />
            ))}
          </div>

          {/* click zones */}
          {!isCover && <div className="cz cz-l" onClick={() => flip('backward')}><span className="cz-icon">‹</span></div>}
          {!isLast   && <div className="cz cz-r" onClick={() => flip('forward')} ><span className="cz-icon">›</span></div>}
        </div>
      </div>

      {/* controls */}
      <div className="controls">
        <button className="nav-btn" onClick={() => flip('backward')} disabled={isCover || flipping}>←</button>
        <div className="progress-track"><div className="progress-fill" style={{width:`${progress}%`}}/></div>
        <span className="spread-label">{spreadLabel}</span>
        <button className="nav-btn" onClick={() => flip('forward')}  disabled={isLast  || flipping}>→</button>
      </div>

      <p className="key-hint">← → arrow keys · click page edges</p>
    </div>
  );
}
